def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    n = len(bins)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        base_score = 0
        if ratio > 3:
            base_score = 3000 + (ratio - 3) ** 2 * 500
        elif 2 < ratio <= 3:
            base_score = 1500 + (ratio - 2) * 300
        elif 1.5 < ratio <= 2:
            base_score = 800 + (ratio - 1.5) * 200
        elif 1 < ratio <= 1.5:
            base_score = 400 + (ratio - 1) * 150
        elif ratio == 1:
            base_score = 250
        else:
            score_sum = 0
            for j in range(1, 15):
                temp = ((capacity - item) / capacity) ** j
                if temp < 0.03:
                    score_sum += temp * 120 / j
                elif 0.03 <= temp < 0.1:
                    score_sum += temp * 40 / (j ** 1.5)
                elif 0.1 <= temp < 0.3:
                    score_sum += np.log1p(temp) * 20 / (j ** 2)
                else:
                    score_sum += (temp ** 0.5) * 10 / (j ** 3)
                if j % 3 == 0 and score_sum > 1:
                    score_sum *= 0.95
            base_score = 1 / (1 + score_sum)
        priority = base_score
        remainder = capacity - item
        if remainder < 0.15 * capacity:
            priority += remainder * 0.2
            if remainder < 0.05 * capacity:
                priority += 5 / (remainder + 1e-5)
        if item > 0.8 * capacity and item < capacity:
            priority *= 0.85 + 0.1 * np.sin(i + item)
        for m in range(1, 4):
            if i + m < n:
                future_cap = bins[i + m]
                fut_ratio = item / future_cap if future_cap > 0 else float('inf')
                if fut_ratio < ratio:
                    priority += (fut_ratio / (m + 1)) * 0.1
                else:
                    priority -= (ratio / (m + 1)) * 0.05
        if i % 2 == 0:
            priority += np.exp(-capacity / (item + 1))
        else:
            priority -= np.log1p(capacity / (item + 1))
        if priority < 0:
            priority = abs(priority) * 0.5
        priorities[i] = priority
    return priorities
